{
  "status": "glossary_seeded",
  "glossary": [
    {
      "canonical_name": "Presentation layer",
      "aliases": [
        "D.2 layer"
      ],
      "definition": "The half of the redesigned design-large-task skill that owns voice, packet shape, phase orchestration, round-cycle mechanics, and how proof-state is rendered to the designer. Sibling of Proof layer. Depends on Proof; Proof never reaches into Presentation.",
      "source": {
        "explorer": "codebase + prior-art",
        "artifact": "cluster-d-foundation-v1.md §3"
      },
      "sense_constraints": [
        "NOT the entire skill — only the designer-facing half",
        "NOT a UI/web frontend term"
      ],
      "status": "PROPOSED-PENDING-DESIGNER",
      "first_used_round": 0,
      "history": [
        {
          "event": "seeded",
          "round": 0,
          "source": {
            "explorer": "codebase + prior-art",
            "artifact": "cluster-d-foundation-v1.md §3"
          }
        }
      ]
    },
    {
      "canonical_name": "Proof layer",
      "aliases": [
        "D.1 layer"
      ],
      "definition": "The half of the skill that owns the proof MCP, element CRUD, ratification, closure machinery, and the closing-argument envelope. Shipped by D.1 at commit 6387b3f. Read-only inheritance for D.2.",
      "source": {
        "explorer": "codebase + prior-art",
        "artifact": "cluster-d-1-design-00.md"
      },
      "sense_constraints": [],
      "status": "PROPOSED-PENDING-DESIGNER",
      "first_used_round": 0,
      "history": [
        {
          "event": "seeded",
          "round": 0,
          "source": {
            "explorer": "codebase + prior-art",
            "artifact": "cluster-d-1-design-00.md"
          }
        }
      ]
    },
    {
      "canonical_name": "information packet",
      "aliases": [
        "packet",
        "round packet"
      ],
      "definition": "The fixed-shape per-round content unit the designer reads. Six components: insight + intro + facts (3-5 single-sentence bullets) + agent commentary + pessimist commentary + decision.",
      "source": {
        "explorer": "prior-art",
        "artifact": "cluster-d-foundation-v1.md §11 architectural commitments"
      },
      "sense_constraints": [
        "NOT a network packet",
        "Six components are designer-locked from cluster-D foundation"
      ],
      "status": "PROPOSED-PENDING-DESIGNER",
      "first_used_round": 0,
      "history": [
        {
          "event": "seeded",
          "round": 0,
          "source": {
            "explorer": "prior-art",
            "artifact": "cluster-d-foundation-v1.md §11 architectural commitments"
          }
        }
      ]
    },
    {
      "canonical_name": "PM register",
      "aliases": [
        "PM voice",
        "designer voice"
      ],
      "definition": "The voice register all designer-facing output runs under: language a product manager (decision authority, no codebase knowledge) can follow without stopping. The Translation Gate enforces this on every output.",
      "source": {
        "explorer": "codebase",
        "artifact": "skills/design-large-task/SKILL.md Translation Gate section"
      },
      "sense_constraints": [],
      "status": "PROPOSED-PENDING-DESIGNER",
      "first_used_round": 0,
      "history": [
        {
          "event": "seeded",
          "round": 0,
          "source": {
            "explorer": "codebase",
            "artifact": "skills/design-large-task/SKILL.md Translation Gate section"
          }
        }
      ]
    },
    {
      "canonical_name": "decision venue",
      "aliases": [
        "venue"
      ],
      "definition": "A well-framed presentation of one architectural choice the designer is in a position to make: agent-supplied research and framing, designer-supplied decision. Each round constructs and presents one venue, then waits for designer judgment.",
      "source": {
        "explorer": "prior-art",
        "artifact": "rebuild-design-derivation-organizing-principle-research-2026-05-05.md"
      },
      "sense_constraints": [
        "NOT a question to the designer",
        "NOT a topic survey — a single decision presented for ratification"
      ],
      "status": "PROPOSED-PENDING-DESIGNER",
      "first_used_round": 0,
      "history": [
        {
          "event": "seeded",
          "round": 0,
          "source": {
            "explorer": "prior-art",
            "artifact": "rebuild-design-derivation-organizing-principle-research-2026-05-05.md"
          }
        }
      ]
    },
    {
      "canonical_name": "pessimist commentary",
      "aliases": [],
      "definition": "A required component of the information packet: 1-2 sentences naming what is fragile, contradictory, or uncomfortable about the round's direction. Drawn from one of five locked categories: foreclosure / fragility / tension / real uncertainty / surprise. Selection mechanism is open in D.2.",
      "source": {
        "explorer": "prior-art",
        "artifact": "cluster-d-foundation-v1.md + sprint-d-2 brief §12"
      },
      "sense_constraints": [
        "Five categories are designer-locked",
        "Selection mechanism is the open question"
      ],
      "status": "PROPOSED-PENDING-DESIGNER",
      "first_used_round": 0,
      "history": [
        {
          "event": "seeded",
          "round": 0,
          "source": {
            "explorer": "prior-art",
            "artifact": "cluster-d-foundation-v1.md + sprint-d-2 brief §12"
          }
        }
      ]
    },
    {
      "canonical_name": "closing argument envelope",
      "aliases": [
        "envelope",
        "closure envelope"
      ],
      "definition": "The structured artifact returned by present_closing_argument: problem statement, ratified Concerns + RCs + NCs + Definitions, phantoms, friction, rules, permissions, risks, and per-element closureProvenance audit chain. Canonical input to the design brief render at Closure.",
      "source": {
        "explorer": "codebase",
        "artifact": "skills/design-large-task/proof-mcp/closing-argument.js"
      },
      "sense_constraints": [],
      "status": "PROPOSED-PENDING-DESIGNER",
      "first_used_round": 0,
      "history": [
        {
          "event": "seeded",
          "round": 0,
          "source": {
            "explorer": "codebase",
            "artifact": "skills/design-large-task/proof-mcp/closing-argument.js"
          }
        }
      ]
    },
    {
      "canonical_name": "two-yes closure gate",
      "aliases": [
        "two-yes gate"
      ],
      "definition": "Closure requires designer consent twice in the same round: first 'yes' on present_closing_argument (view), second 'yes' on confirm_closure_go. Any state mutation between the two clears both flags and forces re-presentation.",
      "source": {
        "explorer": "codebase + prior-art",
        "artifact": "cluster-b-2 inheritance, NC-11 in D.1"
      },
      "sense_constraints": [],
      "status": "PROPOSED-PENDING-DESIGNER",
      "first_used_round": 0,
      "history": [
        {
          "event": "seeded",
          "round": 0,
          "source": {
            "explorer": "codebase + prior-art",
            "artifact": "cluster-b-2 inheritance, NC-11 in D.1"
          }
        }
      ]
    },
    {
      "canonical_name": "coordinate placement",
      "aliases": [
        "coordinate",
        "placement"
      ],
      "definition": "The current location of the work in the two-axis problem space (Structured ⊥ Bounded). Tracked as proof-state property; rendered to the designer in the first round and on every axis-cross thereafter, not per-round.",
      "source": {
        "explorer": "prior-art",
        "artifact": "structured-bounded-problem-space-reference.md"
      },
      "sense_constraints": [],
      "status": "PROPOSED-PENDING-DESIGNER",
      "first_used_round": 0,
      "history": [
        {
          "event": "seeded",
          "round": 0,
          "source": {
            "explorer": "prior-art",
            "artifact": "structured-bounded-problem-space-reference.md"
          }
        }
      ]
    },
    {
      "canonical_name": "single-topic discipline",
      "aliases": [],
      "definition": "Each round addresses exactly one topic. Multi-topic rounds are prohibited; surplus topics queue for subsequent rounds in priority order. Designer-locked from cluster-D foundation.",
      "source": {
        "explorer": "prior-art",
        "artifact": "cluster-d-foundation-v1.md §11"
      },
      "sense_constraints": [],
      "status": "PROPOSED-PENDING-DESIGNER",
      "first_used_round": 0,
      "history": [
        {
          "event": "seeded",
          "round": 0,
          "source": {
            "explorer": "prior-art",
            "artifact": "cluster-d-foundation-v1.md §11"
          }
        }
      ]
    },
    {
      "canonical_name": "decision-authority substitution",
      "aliases": [
        "substitution",
        "PM-bypass"
      ],
      "definition": "Failure mode in which the agent makes a decision that should belong to the designer, particularly when the designer cannot detect the substitution because they lack the technical context to recognize implementation-altitude options dressed as architectural choices. Named in master-plan §4.5 cluster-D charter Concern #7 but omitted from sprint-d-2 brief.",
      "source": {
        "explorer": "prior-art",
        "artifact": "master-plan.md §4.5 + organizing-principle-research-2026-05-05.md"
      },
      "sense_constraints": [
        "NOT every agent draft — only when agent draft locks a decision the PM did not consciously ratify"
      ],
      "status": "PROPOSED-PENDING-DESIGNER",
      "first_used_round": 0,
      "history": [
        {
          "event": "seeded",
          "round": 0,
          "source": {
            "explorer": "prior-art",
            "artifact": "master-plan.md §4.5 + organizing-principle-research-2026-05-05.md"
          }
        }
      ]
    },
    {
      "canonical_name": "closing-argument render protocol",
      "aliases": [],
      "definition": "The designer-facing presentation step that translates the closing-argument envelope (structured data) into prose the designer reads before saying go. Currently unspecified in SKILL.md — gap surfaced by codebase review.",
      "source": {
        "explorer": "codebase",
        "artifact": "skills/design-large-task/SKILL.md Phase 5 Closure"
      },
      "sense_constraints": [
        "NOT the brief render at Closure — separate step happening at present_closing_argument time"
      ],
      "status": "PROPOSED-PENDING-DESIGNER",
      "first_used_round": 0,
      "history": [
        {
          "event": "seeded",
          "round": 0,
          "source": {
            "explorer": "codebase",
            "artifact": "skills/design-large-task/SKILL.md Phase 5 Closure"
          }
        }
      ]
    },
    {
      "canonical_name": "round cycle",
      "aliases": [
        "Phase 4"
      ],
      "definition": "Phase 4 of the redesigned six-phase skill: the iterative loop in which one decision venue per round is researched, framed, presented, and ratified or redirected by the designer. Continues until the designer approves the closing argument.",
      "source": {
        "explorer": "prior-art",
        "artifact": "cluster-d-foundation-v1.md §4 six-phase outline"
      },
      "sense_constraints": [],
      "status": "PROPOSED-PENDING-DESIGNER",
      "first_used_round": 0,
      "history": [
        {
          "event": "seeded",
          "round": 0,
          "source": {
            "explorer": "prior-art",
            "artifact": "cluster-d-foundation-v1.md §4 six-phase outline"
          }
        }
      ]
    },
    {
      "canonical_name": "swap-line architecture",
      "aliases": [
        "plug-in architecture",
        "ACTIVE_UNDERSTANDING_MCP"
      ],
      "definition": "The existing plug-in mechanism in SKILL.md (ACTIVE_UNDERSTANDING_MCP comment-block variable + per-flow references/* file + multi-package MCP server arrangement) that lets one design-large-task skill swap among classic / problemfocused / team-interview flows. Open in D.2: keep, become a fourth flow under it, or eliminate.",
      "source": {
        "explorer": "codebase",
        "artifact": "skills/design-large-task/SKILL.md lines 9-78"
      },
      "sense_constraints": [],
      "status": "PROPOSED-PENDING-DESIGNER",
      "first_used_round": 0,
      "history": [
        {
          "event": "seeded",
          "round": 0,
          "source": {
            "explorer": "codebase",
            "artifact": "skills/design-large-task/SKILL.md lines 9-78"
          }
        }
      ]
    }
  ],
  "seeded_count": 14
}

